-- Regenerate with: node scripts/generate-backend-truth.mjs
-- Session 2 — Carry an optional org membership through the project invite
-- flow. When the inviter belongs to an active org, they may opt to also
-- add the invitee to that org on accept. The org_id is captured at invite
-- creation; acceptance reads it from the invite row.

alter table public.project_invites
  add column if not exists add_to_org_id uuid
    references public.organizations(id) on delete set null;

create or replace function public.accept_project_invite(p_invite_token text)
returns public.project_invites
language plpgsql
security definer
set search_path = public
as $$
declare
  v_invite public.project_invites%rowtype;
  v_profile_email text;
  v_owner_profile_id uuid;
  v_already_accepted_by_current_user boolean := false;
  v_org_id uuid;
  v_inviter_in_org boolean;
begin
  if auth.uid() is null then
    raise exception 'Authentication required';
  end if;

  select *
  into v_invite
  from public.project_invites
  where invite_token = p_invite_token
  for update;

  if not found then
    raise exception 'Invite not found';
  end if;

  if v_invite.status = 'accepted' and v_invite.accepted_profile_id = auth.uid() then
    v_already_accepted_by_current_user := true;
  elsif v_invite.status <> 'pending' then
    raise exception 'Invite is no longer pending';
  end if;

  select p.email
  into v_profile_email
  from public.profiles p
  where p.id = auth.uid();

  if not found then
    raise exception 'Profile not found';
  end if;

  if not v_already_accepted_by_current_user
     and (v_profile_email is null or lower(v_profile_email) <> lower(v_invite.email)) then
    raise exception 'Invite email does not match the current account';
  end if;

  select p.owner_profile_id
  into v_owner_profile_id
  from public.projects p
  where p.id = v_invite.project_id;

  if not found then
    raise exception 'Project not found';
  end if;

  if v_invite.role = 'owner'
     and v_owner_profile_id is distinct from auth.uid() then
    raise exception 'Owner invites are not supported without a project ownership transfer';
  end if;

  -- Acceptance should honor a previously created invite even if inviter authority changed later.
  -- Delegate authority-trigger checks to project owner for acceptance flow.
  perform set_config('app.member_delegate_actor', v_owner_profile_id::text, true);

  begin
    insert into public.project_members (
      project_id,
      profile_id,
      role,
      ai_access,
      viewer_regime,
      credit_limit,
      used_credits,
      finance_visibility,
      internal_docs_visibility
    )
    values (
      v_invite.project_id,
      auth.uid(),
      v_invite.role,
      v_invite.ai_access,
      v_invite.viewer_regime,
      v_invite.credit_limit,
      0,
      v_invite.finance_visibility,
      v_invite.internal_docs_visibility
    )
    on conflict (project_id, profile_id) do update
      set role = excluded.role,
          ai_access = excluded.ai_access,
          viewer_regime = excluded.viewer_regime,
          credit_limit = excluded.credit_limit,
          finance_visibility = excluded.finance_visibility,
          internal_docs_visibility = excluded.internal_docs_visibility;

    if not v_already_accepted_by_current_user then
      update public.project_invites
      set status = 'accepted',
          accepted_profile_id = auth.uid(),
          accepted_at = coalesce(accepted_at, now())
      where id = v_invite.id
      returning * into v_invite;
    end if;
  exception
    when others then
      perform set_config('app.member_delegate_actor', '', true);
      raise;
  end;

  perform set_config('app.member_delegate_actor', '', true);

  -- Optional org membership add. Validates that the inviter is still a
  -- member of the target org before adding the acceptee. If the inviter has
  -- left the org by acceptance time, we silently skip the org add — the
  -- project membership remains valid (graceful degradation).
  v_org_id := v_invite.add_to_org_id;
  if v_org_id is not null then
    select exists (
      select 1
      from public.organizations o
      where o.id = v_org_id and o.owner_profile_id = v_invite.invited_by
    ) or exists (
      select 1
      from public.org_members om
      where om.org_id = v_org_id and om.profile_id = v_invite.invited_by
    )
    into v_inviter_in_org;

    if v_inviter_in_org then
      insert into public.org_members (org_id, profile_id, role)
      values (v_org_id, auth.uid(), 'member')
      on conflict (org_id, profile_id) do nothing;
    end if;
  end if;

  return v_invite;
end;
$$;
